namespace sv_6ccca302b40d4b8b96ef1a5a165b7378;

public enum ScreenSize
{
    Mobile,
    Tablet,
    Desktop
}

@implements IAsyncDisposable
@inject IJSRuntime JS

<CascadingValue Value="currentSize" Name="ScreenSize">
    @ChildContent
</CascadingValue>

@code {
    [Parameter]
    public RenderFragment? ChildContent { get; set; }

    private ScreenSize currentSize = ScreenSize.Desktop;
    private IJSObjectReference? module;
    private DotNetObjectReference<ScreenSizeProvider>? dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        dotNetRef = DotNetObjectReference.Create(this);
        module = await JS.InvokeAsync<IJSObjectReference>(
            "import",
            "./_content/sv-6ccca302b40d4b8b96ef1a5a165b7378/Components/ScreenSizeProvider.razor.js");
        await module.InvokeVoidAsync("initialize", dotNetRef);
    }

    [JSInvokable]
    public void OnViewportCategoryChanged(string category)
    {
        var newSize = category switch
        {
            "Mobile" => ScreenSize.Mobile,
            "Tablet" => ScreenSize.Tablet,
            _ => ScreenSize.Desktop
        };

        if (newSize != currentSize)
        {
            currentSize = newSize;
            StateHasChanged();
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (module is not null)
        {
            try
            {
                await module.InvokeVoidAsync("dispose");
                await module.DisposeAsync();
            }
            catch (JSDisconnectedException)
            {
                // Circuit may already be gone
            }
        }

        dotNetRef?.Dispose();
    }
}

let resizeHandler = null;

function getCategory() {
    const width = window.innerWidth;
    if (width < 768) return "Mobile";
    if (width < 1024) return "Tablet";
    return "Desktop";
}

export function initialize(dotNetRef) {
    // Send the initial category immediately
    dotNetRef.invokeMethodAsync("OnViewportCategoryChanged", getCategory());

    let lastCategory = getCategory();

    resizeHandler = () => {
        const current = getCategory();
        if (current !== lastCategory) {
            lastCategory = current;
            dotNetRef.invokeMethodAsync("OnViewportCategoryChanged", current);
        }
    };

    window.addEventListener("resize", resizeHandler);
}

export function dispose() {
    if (resizeHandler) {
        window.removeEventListener("resize", resizeHandler);
        resizeHandler = null;
    }
}

